// src/lib/firebase.js
// ─── PEGÁ TUS CREDENCIALES DE FIREBASE ACÁ ─────────────────────────────────
// Firebase Console → Tu proyecto → Configuración → Agregar app web
import { initializeApp } from "firebase/app";
import { getFirestore, enableIndexedDbPersistence } from "firebase/firestore";
import { getStorage } from "firebase/storage";

const firebaseConfig = {
  apiKey: "AIzaSyBFN8fIosDVB4EBesb6HODy_Y9VRhShTfA",
  authDomain: "rendimiento-gym.firebaseapp.com",
  projectId: "rendimiento-gym",
  storageBucket: "rendimiento-gym.appspot.com",
  messagingSenderId: "1075510522670",
  appId: "1:1075510522670:web:38ec4376ba867cb2f7c0bf"
};

// ───────────────────────────────────────────────────────────────────────────

const app = initializeApp(firebaseConfig);
export const db      = getFirestore(app);
export const storage = getStorage(app);

// Persistencia offline: los datos quedan cacheados en el dispositivo
enableIndexedDbPersistence(db).catch(err => {
  if (err.code === "failed-precondition") console.warn("Offline: múltiples tabs abiertas.");
  else if (err.code === "unimplemented")  console.warn("Offline no soportado en este browser.");
});
